--! cl_fix_set_msb implementation		
function cl_fix_set_msb (	a			: std_logic_vector; 
							a_fmt		: FixFormat_t; 
							index		: natural;
							value		: std_logic) 
							return std_logic_vector is
	variable a_v : std_logic_vector (a'length-1 downto 0);
begin
	a_v := a;
	a_v (a_v'high-index) := value;
	return a_v;
end;

